<template>
  <div class="h5-container">
    <!-- 进度指示器 -->
    <div class="progress-indicator">
      <div
        v-for="(page, index) in pages"
        :key="index"
        class="dot-item"
        :class="{ 'tooltip-visible': currentIndex === index || activeTooltip === index }"
        @click="handleDotClick(index)"
        @mouseenter="activeTooltip = index"
        @mouseleave="activeTooltip = null"
      >
        <span class="dot-tooltip">{{ page.title }}</span>
        <div
          class="progress-dot"
          :class="{ active: currentIndex === index }"
        ></div>
      </div>
    </div>

    <!-- 页面内容 -->
    <div class="page-wrapper" ref="pageWrapper">
      <transition :name="transitionName" mode="out-in">
        <router-view :key="$route.path" />
      </transition>
    </div>

    <!-- 导航按钮 -->
    <div class="nav-buttons" v-if="!isFirstPage && !isLastPage">
      <el-button
        v-if="!isFirstPage"
        class="nav-btn prev-btn"
        icon="el-icon-arrow-up"
        circle
        @click="prevPage"
      ></el-button>
      <el-button
        v-if="!isLastPage"
        class="nav-btn next-btn"
        icon="el-icon-arrow-down"
        circle
        @click="nextPage"
      ></el-button>
    </div>
  </div>
</template>

<script>
export default {
  name: 'H5Container',
  data() {
    return {
      pages: [
        { path: '/intro', title: '开篇引导' },
        { path: '/background', title: '3号线概况' },
        { path: '/data-visualization', title: '租金数据可视化' },
        { path: '/reality-gap', title: '生存经济学分析' },
        { path: '/interaction', title: '通勤成本计算器' },
        { path: '/ending', title: '结语' }
      ],
      currentIndex: 0,
      transitionName: 'slide-down',
      activeTooltip: null,
      tooltipTimer: null
    }
  },
  computed: {
    isFirstPage() {
      return this.currentIndex === 0
    },
    isLastPage() {
      return this.currentIndex === this.pages.length - 1
    }
  },
  watch: {
    '$route.path': {
      handler(newPath) {
        const index = this.pages.findIndex(p => p.path === newPath)
        if (index !== -1) {
          this.currentIndex = index
        }
      },
      immediate: true
    }
  },
  methods: {
    handleDotClick(index) {
      // 手机端：先展示 tooltip，再跳转（如已在当前页则只显示 tooltip）
      if (index !== this.currentIndex) {
        this.goToPage(index)
      }
      // 触发 tooltip 显示，1.5s 后自动收起（移动端无 hover）
      this.activeTooltip = index
      clearTimeout(this.tooltipTimer)
      this.tooltipTimer = setTimeout(() => {
        this.activeTooltip = null
      }, 1500)
    },
    goToPage(index) {
      if (index !== this.currentIndex) {
        this.transitionName = index > this.currentIndex ? 'slide-down' : 'slide-up'
        this.$router.push(this.pages[index].path)
      }
    },
    nextPage() {
      if (!this.isLastPage) {
        this.transitionName = 'slide-down'
        this.$router.push(this.pages[this.currentIndex + 1].path)
      }
    },
    prevPage() {
      if (!this.isFirstPage) {
        this.transitionName = 'slide-up'
        this.$router.push(this.pages[this.currentIndex - 1].path)
      }
    },
  }
}
</script>

<style scoped>
.page-wrapper {
  position: relative;
  overflow: hidden;
}

/* 导航按钮 */
.nav-buttons {
  position: fixed;
  right: 20px;
  bottom: 30px;
  z-index: 999;
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.nav-btn {
  width: 50px;
  height: 50px;
  background: linear-gradient(135deg, #0066CC, #0099FF);
  border: none;
  color: #fff;
  font-size: 20px;
  box-shadow: 0 4px 12px rgba(0, 102, 204, 0.3);
}

.nav-btn:hover {
  transform: scale(1.1);
  box-shadow: 0 6px 16px rgba(0, 102, 204, 0.4);
}

/* 页面切换动画 */
.slide-down-enter-active,
.slide-down-leave-active,
.slide-up-enter-active,
.slide-up-leave-active {
  transition: all 0.5s ease;
}

.slide-down-enter {
  transform: translateY(100%);
  opacity: 0;
}

.slide-down-leave-to {
  transform: translateY(-100%);
  opacity: 0;
}

.slide-up-enter {
  transform: translateY(-100%);
  opacity: 0;
}

.slide-up-leave-to {
  transform: translateY(100%);
  opacity: 0;
}

@media (max-width: 750px) {
  .nav-buttons {
    right: 15px;
    bottom: 20px;
  }
  
  .nav-btn {
    width: 45px;
    height: 45px;
  }
}
</style>




